#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int solve(vector<int>& values, int left, int right) {
        if (right - left + 1 <= 2) return 0;
        int op1 = values[left] + values[left + 1] + solve(values, left + 2, right);
        int op2 = values[right] + values[right - 1] + solve(values, left, right - 2);
        int op3 = values[left] + values[right] + solve(values, left + 1, right - 1);
        return max({op1, op2, op3});
    }

    int maximizeLineupScore(vector<int>& values) {
        return solve(values, 0, values.size() - 1);
    }
};

