            if (!used[i] && orders[i][0] == staffLevels[index]) {
                used[i] = true;
                long long profit = orders[i][1] + backtrack(staffLevels, orders, used, index + 1, extraUsed);
                optimizeCateringRevenue = max(optimizeCateringRevenue, profit);
                used[i] = false;
            }
