        unordered_map<int, int> map1;
        for (int w : staffLevels) map1[w]++;
        unordered_map<int, priority_queue<int>> mp;
        for (auto &task : orders) {
            mp[task[0]].push(task[1]);
        }
        for (auto &p : mp) {
            int k = p.first;
            if (map1.count(k)) {
                auto &pq = p.second;
                if (map1[k] >= pq.size()) {
                    while (!pq.empty()) {
                        ans += pq.top();
                        pq.pop();
                    }
                } else {
                    int a = map1[k];
                    while (a-- > 0) {
                        ans += pq.top();
                        pq.pop();
                    }
                }
            }
        }
        int mx = INT_MIN;
        for (auto &p : mp) {
            if (!p.second.empty()) {
                mx = max(mx, p.second.top());
                p.second.pop();
            }
        }
        if (mx != INT_MIN) ans += mx;
        return ans;
    }
};

