#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    map<int, int> minh;                     
    map<int, int, greater<int>> maxh;       
    long long s1 = 0, s2 = 0;
    int cnt1 = 0, cnt2 = 0;

    long long stabilizeBeatWindow(vector<int>& levels, int k) {
        int n = levels.size();
        long long res = LLONG_MAX;
        for (int i = 0, j = 0; i < n; i++) {
            add(levels[i]);
            if (i - j + 1 == k) {
                res = min(res, cal());
                remove(levels[j++]);
            }
        }
        return res;
    }

    long long cal() {
        int tot = cnt1 + cnt2;
        int med;
        if (tot % 2 == 1)
            med = minh.begin()->first;
        else
            med = (minh.begin()->first + maxh.begin()->first) / 2;
        return s1 - 1LL * med * cnt1 + 1LL * med * cnt2 - s2;
    }

    void add(int x) {
        maxh[x]++;
        s2 += x;
        cnt2++;
        int y = maxh.begin()->first;
        if (--maxh[y] == 0) maxh.erase(y);
        s2 -= y;
        cnt2--;
        minh[y]++;
        s1 += y;
        cnt1++;
        rebalance();
    }

    void rebalance() {
        if (cnt1 - cnt2 > 1) {
            int x = minh.begin()->first;
            if (--minh[x] == 0) minh.erase(x);
            s1 -= x;
            cnt1--;
            maxh[x]++;
            s2 += x;
            cnt2++;
        }
    }

    void remove(int x) {
        if (minh.count(x)) {
            if (--minh[x] == 0) minh.erase(x);
            s1 -= x;
            cnt1--;
        } else {
            if (--maxh[x] == 0) maxh.erase(x);
            s2 -= x;
            cnt2--;
        }
        rebalance();
    }
