import heapq

class solution:
    def stabilizeBeatWindow(self, nums, k) :
        lo = []
        hi = []
        membership = [-1] * len(nums)
        lo_sum = hi_sum = lo_sz = hi_sz = 0
        def median(i):
            while hi[0][1] <= i - k:
                heapq.heappop(hi)
            return hi[0][0]
        def pop(pq, i):
            while pq[0][1] <= i - k:
                heapq.heappop(pq)
            x, j = heapq.heappop(pq)
            return x, j
        def push(i):
            nonlocal hi_sz, hi_sum, lo_sz, lo_sum
            x = nums[i]

            heapq.heappush(hi, (x, i))
            hi_sum += x
            membership[i] = 1

            y, j = pop(hi, i)
            hi_sum -= y

            heapq.heappush(lo, (-y, j))
            membership[j] = 0
            lo_sz += 1
            lo_sum += y

            rebalance(i)
        def rebalance(i):
            nonlocal hi_sz, hi_sum, lo_sz, lo_sum
            if lo_sz > hi_sz:
                x, j = pop(lo, i)
                lo_sz -= 1
                lo_sum += x

                heapq.heappush(hi, (-x, j))
                hi_sz += 1
                hi_sum -= x
                membership[j] = 1
        res = float('inf')
        for i in range(len(nums)):
            push(i)
            if i < k - 1:
                continue
            if k % 2 == 0:
                res = min(res, hi_sum - lo_sum)
            else:
                res = min(res, hi_sum - lo_sum - median(i))
            if membership[i - (k - 1)] == 1:
                hi_sz -= 1
                hi_sum -= nums[i - (k - 1)]
            else:
                lo_sz -= 1
                lo_sum -= nums[i - (k - 1)]
            membership[i - (k - 1)] = -1
        return res

