class PriorityQueue {
    constructor(compare) {
        this.heap = [];
        this.compare = compare;
    }

    size() {
        return this.heap.length;
    }

    isEmpty() {
        return this.size() === 0;
    }

    front() {
        return this.heap[0];
    }

    enqueue(val) {
        this.heap.push(val);
        this._heapifyUp();
    }

    dequeue() {
        if (this.size() === 1) return this.heap.pop();

        const top = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._heapifyDown();

        return top;
    }

    _heapifyUp() {
        let i = this.size() - 1;

        while (i > 0) {
            let parent = Math.floor((i - 1) / 2);

            if (this.compare(this.heap[i], this.heap[parent]) < 0) {
                [this.heap[i], this.heap[parent]] = [this.heap[parent], this.heap[i]];
                i = parent;
            } else break;
        }
    }

    _heapifyDown() {
        let i = 0;
        let n = this.size();

        while (true) {
            let left = 2 * i + 1;
            let right = 2 * i + 2;
            let best = i;

            if (left < n && this.compare(this.heap[left], this.heap[best]) < 0) {
                best = left;
            }

            if (right < n && this.compare(this.heap[right], this.heap[best]) < 0) {
                best = right;
            }

            if (best !== i) {
                [this.heap[i], this.heap[best]] = [this.heap[best], this.heap[i]];
                i = best;
            } else break;
        }
    }
}

class Solution {
    stabilizeBeatWindow (levels, k) {
        const n = levels.length;
        const min_pq = new PriorityQueue((a, b) => a[0] < b[0] ? -1 : 1);
        const max_pq = new PriorityQueue((a, b) => a[0] > b[0] ? -1 : 1);
        let max_pq_size = Math.ceil(k / 2);
        let min_pq_size = k - max_pq_size;
        let total = 0;
        for (let i = 0; i < k; i++) {
            total += levels[i];
            max_pq.enqueue([levels[i], i]);
        }
        let min_sum = 0;
        let min_pq_indices = new Set();
        for (let i = 0; i < min_pq_size; i++) {
            const [num, idx] = max_pq.dequeue();
            min_sum += num;
            min_pq.enqueue([num, idx]);
            min_pq_indices.add(idx);
        }
        let max_sum = total - min_sum;
        let median = max_pq.front()[0];
        let min_ops = Math.abs(median * max_pq_size - max_sum) + Math.abs(min_sum - median * min_pq_size);
        for (let i = k; i < n; i++) {
            const num = levels[i];
            let lo = i - k;
            total += num - levels[lo];
            while (!min_pq.isEmpty() && min_pq.front()[1] <= lo) min_pq.dequeue();
            while (!max_pq.isEmpty() && max_pq.front()[1] <= lo) max_pq.dequeue();
            if (min_pq_indices.has(lo)) {
                min_pq_indices.delete(lo);
                min_sum -= levels[lo];
                max_pq.enqueue([num, i]);
                let [_num, _idx] = max_pq.dequeue();
                min_sum += _num;
                min_pq.enqueue([_num, _idx]);
                min_pq_indices.add(_idx);
            } else {
                min_pq.enqueue([num, i]);
                min_sum += num;
                min_pq_indices.add(i);
                let [_num, _idx] = min_pq.dequeue();
                min_pq_indices.delete(_idx);
                min_sum -= _num;
                max_pq.enqueue([_num, _idx]);
            }
            let max_sum = total - min_sum;
            while (!max_pq.isEmpty() && max_pq.front()[1] <= lo) max_pq.dequeue();
            let median = max_pq.front()[0];
            min_ops = Math.min(min_ops,
                Math.abs(median * max_pq_size - max_sum) + Math.abs(min_sum - median * min_pq_size));
        }
        return min_ops;
    }
}

