toArray(node) {
    /*
       Given a node in a doubly linked list,
       convert the entire list into an array
    */
    /* Step 1: Move to the head of the list */
    cur = node
    while (cur.prev is not NULL) {
        cur = cur.prev
    }
    /* Step 2: Find length of the list */
    len = 0
    p = cur
    while (p is not NULL) {
        len = len + 1
        p = p.next
    }
    /* Step 3: Create result array of size len */
    res = array of size len
    /* Step 4: Fill the array by traversing from head */
    idx = 0
    while (cur is not NULL) {
        res[idx] = cur.data
        idx = idx + 1
        cur = cur.next
    }
    return res
}
