class solution {
public:
    int longestExclusiveSegment(string text) {
        int n = text.size();
        vector<vector<int>> pref(26, vector<int>(n + 1, 0));
        vector<int> total(26, 0);
        for (int i = 0; i < n; i++) {
            for (int ch = 0; ch < 26; ch++) {
                pref[ch][i + 1] = pref[ch][i];
            }
            int idx = text[i] - 'a';
            pref[idx][i + 1]++;
            total[idx]++;
        }
        int answer = -1;
        for (int left = 0; left < n; left++) {
            for (int right = left; right < n; right++) {
                int length = right - left + 1;
                if (length == n) {
                    continue;
                }
                bool valid = true;
                for (int ch = 0; ch < 26; ch++) {
                    int inside = pref[ch][right + 1] - pref[ch][left];
                    if (inside > 0 && inside != total[ch]) {
                        valid = false;
                        break;
                    }
                }
                if (valid) {
                    answer = max(answer, length);
                }
            }
        }
        return answer;
    }
};

