    int longestExclusiveSegment(string text) {
        int n = text.size();
        vector<int> first(26, n);
        vector<int> last(26, -1);
        for (int i = 0; i < n; i++) {
            int idx = text[i] - 'a';
            first[idx] = min(first[idx], i);
            last[idx] = i;
