            for (int j = start; j < n; j++) {
                int idx = text[j] - 'a';
                if (first[idx] < start) {
                    break;
                }
                end = max(end, last[idx]);
                if (j == end) {
                    int length = end - start + 1;
                    if (length < n) {
                        answer = max(answer, length);
                    }
                }
            }
        }
        return answer;
    }
