import java.util.*;
import java.io.*;

class Solution {
    public int longestExclusiveSegment(String text) {
        int n = text.length();
        int[] first = new int[26];
        int[] last = new int[26];
        Arrays.fill(first, n);
        Arrays.fill(last, -1);
        for (int i = 0; i < n; i++) {
            int idx = text.charAt(i) - 'a';
            first[idx] = Math.min(first[idx], i);
            last[idx] = i;
        }
        int answer = -1;
        for (int start = 0; start < n; start++) {
            int startIdx = text.charAt(start) - 'a';
            if (first[startIdx] != start) {
                continue;
            }
            int end = -1;
            for (int j = start; j < n; j++) {
                int idx = text.charAt(j) - 'a';
                if (first[idx] < start) {
                    break;
                }
                end = Math.max(end, last[idx]);
                if (j == end) {
                    int length = end - start + 1;
                    if (length < n) {
                        answer = Math.max(answer, length);
                    }
                }
            }
        }
        return answer;
    }
}

