        int ans = 0;
        for (int i = 0; i < n; i++) {
            vector<int> freq(26, 0);
            for (int j = i; j < n; j++) {
                freq[sessionLog[j] - 'a']++;
                if (freq[sessionLog[j] - 'a'] > 1) break;
                ans++;
            }
        }
        return ans;
    }
};

