#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int dp[12][2][2][1024];
    int solve(string &s, int index, int tight, int started, int mask) {
        if (index == (int)s.size()) {
            return started ? 1 : 0;
        }
        if (dp[index][tight][started][mask] != -1) {
            return dp[index][tight][started][mask];
        }
        int limit = tight ? s[index] - '0' : 9;
        int ans = 0;
        for (int digit = 0; digit <= limit; digit++) {
            int newTight = (tight && digit == limit) ? 1 : 0;
            if (!started && digit == 0) {
                ans += solve(s, index + 1, newTight, 0, mask);
            } else {
                if ((mask & (1 << digit)) == 0) {
                    ans += solve(s, index + 1, newTight, 1, mask | (1 << digit));
                }
            }
        }
        return dp[index][tight][started][mask] = ans;
    }
    int countDistinctUpTo(int num) {
        if (num <= 0) {
            return 0;
        }
        string s = to_string(num);
        memset(dp, -1, sizeof(dp));
        return solve(s, 0, 1, 0, 0);
    }
    int distinctCount(int startVal, int endVal) {
        return countDistinctUpTo(endVal) - countDistinctUpTo(startVal - 1);
    }
};

