    mask = 0
    /* Extract digits one by one until the number becomes 0 */
    while (num > 0) {
        /* Take the last digit */
        digit = num % 10
        /* If this digit is already present in the mask, number is invalid */
        if (mask AND (1 << digit)) {
            return false
        }
        /* Mark this digit as used in the mask */
        mask = mask OR (1 << digit)
        /* Remove the last digit from the number */
        num = num / 10
    }
    /* If no digit repeats, number is valid */
    return true
}
distinctCount(startVal, endVal) {
    count = 0
    /* Check every number in the range */
    for (num = startVal to endVal) {
        /* If current number has all distinct digits, count it */
        if (isDistinctDigit(num)) {
            count = count + 1
        }
    }
    /* Return the final count */
    return count
}
