class Solution {
    static isDistinctDigit(num) {
        let mask = 0;
        while (num > 0) {
            const digit = num % 10;
            if (mask & (1 << digit)) {
                return false;
            }
            mask |= (1 << digit);
            num = Math.floor(num / 10);
        }
        return true;
    }
    static distinctCount(startVal, endVal) {
        let count = 0;
        for (let num = startVal; num <= endVal; num++) {
            if (this.isDistinctDigit(num)) {
                count++;
            }
        }
        return count;
    }
}

