class solution {
public:
    int maxProcessedQueries(vector<int>& values, vector<int>& limits) {
        int n = values.size();
        int m = limits.size();
        int answer = 0;
        vector<vector<int>> dp(n, vector<int>(n, 0));
        for (int gap = n - 1; gap >= 0; gap--) {
            for (int i = 0; i + gap < n; i++) {
                int j = i + gap;
                if (i > 0) {
                    int processed = dp[i - 1][j];
                    if (processed < m && values[i - 1] >= limits[processed]) {
                        dp[i][j] = max(dp[i][j], processed + 1);
                    } else {
                        dp[i][j] = max(dp[i][j], processed);
                    }
                }
                if (j + 1 < n) {
                    int processed = dp[i][j + 1];
                    if (processed < m && values[j + 1] >= limits[processed]) {
                        dp[i][j] = max(dp[i][j], processed + 1);
                    } else {
                        dp[i][j] = max(dp[i][j], processed);
                    }
                }
                if (dp[i][j] == m) {
                    return m;
                }
            }
        }
        for (int i = 0; i < n; i++) {
            int processed = dp[i][i];
            if (processed < m && values[i] >= limits[processed]) {
                answer = max(answer, processed + 1);
            } else {
                answer = max(answer, processed);
            }
        }
        return answer;
    }
